mapper.select:
SELECT * FROM medicine
name LIKE CONCAT('%', #{name}, '%') AND code LIKE CONCAT('%', #{code}, '%')
ORDER BY create_time DESC LIMIT #{offset}, #{size}

mapper.update:
UPDATE medicine
name = #{med.name}, specification = #{med.specification}, unit = #{med.unit}, price = #{med.price}, stock = #{med.stock}, min_stock = #{med.minStock}, supplier = #{med.supplier}, status = #{med.status}, update_time = NOW()
WHERE id = #{med.id}
